            av = &pv[n];
            len = pv[n].name.len;
        }
    }
    if (av) {
        v[i].get_handler = av->get_handler;
        v[i].data = (uintptr_t) &v[i].name;
        v[i].flags = av->flags;
        goto next;
    }

    if (v[i].get_handler == NULL) {
        ngx_log_error(NGX_LOG_EMERG, cf->log, 0, "unknown \"%V\" variable", &v[i].name);
